#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char *s = (char*)malloc((N+5)*sizeof(char));
        scanf("%s", s);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            for (int d = 1; d <= 9; ++d) {
                int j = i + d;
                if (j >= N) break;
                int diff = abs((s[j]-'0') - (s[i]-'0'));
                if (diff == d) ++ans;
            }
        }
        printf("%lld\n", ans);
        free(s);
    }
    return 0;
}

