import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        S = next(it)
        ans = 0
        for i in range(N):
            di = ord(S[i]) - 48
            for d in range(1, 10):
                j = i + d
                if j >= N:
                    break
                dj = ord(S[j]) - 48
                if abs(dj - di) == d:
                    ans += 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

